**Order Controller with Transaction:**

```javascript
// controllers/orderController.js
const mongoose = require('mongoose');
const Order = require('../models/Order');
const Cart = require('../models/Cart');
const Product = require('../models/Product');
const asyncHandler = require('../utils/asyncHandler');
const AppError = require('../utils/AppError');

exports.createOrder = asyncHandler(async (req, res, next) => {
  const { shippingAddress, paymentMethod } = req.body;

  // Get cart
  const cart = await Cart.findOne({ user: req.user._id })
    .populate('items.product');

  if (!cart || cart.items.length === 0) {
    return next(new AppError('Cart is empty', 400));
  }

  // Start transaction
  const session = await mongoose.startSession();
  session.startTransaction();

  try {
    const orderItems = [];

    // Validate stock and update inventory
    for (const item of cart.items) {
      const product = await Product.findById(item.product._id).session(session);

      if (!product) {
        throw new AppError(`Product not found: ${item.product.name}`, 404);
      }

      if (product.stock < item.quantity) {
        throw new AppError(
          `Insufficient stock for ${product.name}. Available: ${product.stock}`,
          400
        );
      }

      // Reduce stock
      product.stock -= item.quantity;
      await product.save({ session });

      orderItems.push({
        product: product._id,
        name: product.name,
        price: item.price,
        quantity: item.quantity
      });
    }

    // Calculate totals
    const subtotal = cart.totalAmount;
    const shippingCost = subtotal >= 100 ? 0 : 10;
    const tax = subtotal * 0.1;
    const totalAmount = subtotal + shippingCost + tax;

    // Create order
    const [order] = await Order.create([{
      user: req.user._id,
      items: orderItems,
      shippingAddress,
      paymentMethod,
      subtotal,
      shippingCost,
      tax,
      totalAmount
    }], { session });

    // Clear cart
    cart.items = [];
    await cart.save({ session });

    // Commit transaction
    await session.commitTransaction();

    res.status(201).json({
      success: true,
      data: order
    });

  } catch (error) {
    // Rollback on error
    await session.abortTransaction();
    return next(error);
  } finally {
    session.endSession();
  }
});

// Cancel order (restore stock)
exports.cancelOrder = asyncHandler(async (req, res, next) => {
  const order = await Order.findById(req.params.id);

  if (!order) return next(new AppError('Order not found', 404));
  if (order.user.toString() !== req.user._id.toString()) {
    return next(new AppError('Not authorized', 403));
  }
  if (order.orderStatus !== 'pending') {
    return next(new AppError('Can only cancel pending orders', 400));
  }

  const session = await mongoose.startSession();
  session.startTransaction();

  try {
    // Restore stock
    for (const item of order.items) {
      await Product.findByIdAndUpdate(
        item.product,
        { $inc: { stock: item.quantity } },
        { session }
      );
    }

    order.orderStatus = 'cancelled';
    await order.save({ session });

    await session.commitTransaction();

    res.json({ success: true, data: order });

  } catch (error) {
    await session.abortTransaction();
    return next(error);
  } finally {
    session.endSession();
  }
});
```

**Key Points:**
- All operations use same session
- Stock validated before reducing
- Transaction ensures atomicity
- Rollback on any failure
- Cart cleared only after successful order
